#include <fstream>
#include <iostream>
#include <string>
#include <streambuf>

// This macro renames the 'main' function in the student's code
// to 'student_main' during compilation, allowing the driver to have its own 'main'.
#define main student_main

// Declare the student's (renamed) main function
extern int student_main();

int main() {
    // Redirect stdin to read from input.txt
    std::ifstream in_file("input.txt");
    std::streambuf* cin_backup = std::cin.rdbuf();
    std::cin.rdbuf(in_file.rdbuf());

    // Redirect stdout to write to output.txt
    std::ofstream out_file("output.txt");
    std::streambuf* cout_backup = std::cout.rdbuf();
    std::cout.rdbuf(out_file.rdbuf());

    // Call the student's (renamed) main function
    int exit_code = student_main();

    // Restore original cin/cout rdbufs
    std::cin.rdbuf(cin_backup);
    std::cout.rdbuf(cout_backup);

    return exit_code;
}
